/**
 * Look up improvement curves for a discipline + gender.
 * @param {string} discipline  e.g. '100m', 'Shot Put', 'Long Jump'
 * @param {string} gender      'Male' or 'Female'
 * @returns {Object|null} { early, late, steady } each with { rates, p25, p75, n }
 */
export function getImprovementCurves(discipline, gender) {
  const key = `${discipline}_${gender}`;
  return IMPROVEMENT_CURVES[key] || null;
}

/**
 * Project future performance using real improvement curves.
 * Applies the median year-on-year improvement rate at each age
 * to the athlete's current PB, producing a realistic curvilinear projection.
 * 
 * @param {number} currentPB      Current personal best
 * @param {number} currentAge     Current age (integer)
 * @param {string} discipline     e.g. '100m'
 * @param {string} gender         'Male' or 'Female'
 * @param {string} trajectoryType 'early' | 'late' | 'steady'
 * @param {number} maxAge         Project up to this age (default 35)
 * @returns {Array<{age, projected, p25, p75, n}>} Projected performance at each future age
 */
export function projectPerformance(currentPB, currentAge, discipline, gender, trajectoryType = 'steady', maxAge = 35) {
  const curves = getImprovementCurves(discipline, gender);
  if (!curves) return [];
  
  const traj = curves[trajectoryType] || curves.steady;
  if (!traj) return [];
  
  const isDesc = curves.direction === 'desc'; // Higher is better (field events)
  const points = [{ age: currentAge, projected: currentPB, p25: currentPB, p75: currentPB, n: null }];
  
  let projected = currentPB;
  let p25Val = currentPB;
  let p75Val = currentPB;
  
  for (let age = currentAge + 1; age <= maxAge; age++) {
    const rate = traj.rates[age];
    const r25 = traj.p25[age];
    const r75 = traj.p75[age];
    const n = traj.n[age] || 0;
    
    if (rate === undefined) {
      // No data for this age — extrapolate from last known rate with decay
      const lastKnownAge = Math.max(...Object.keys(traj.rates).map(Number).filter(a => a < age));
      if (lastKnownAge && traj.rates[lastKnownAge] !== undefined) {
        const lastRate = traj.rates[lastKnownAge];
        const decayedRate = lastRate * Math.pow(0.85, age - lastKnownAge); // Conservative decay
        if (isDesc) {
          projected *= (1 + decayedRate / 100);
          p25Val *= (1 + (r25 !== undefined ? r25 : decayedRate * 0.6) / 100);
          p75Val *= (1 + (r75 !== undefined ? r75 : decayedRate * 1.4) / 100);
        } else {
          projected *= (1 - decayedRate / 100);
          p25Val *= (1 - (r25 !== undefined ? r25 : decayedRate * 0.6) / 100);
          p75Val *= (1 - (r75 !== undefined ? r75 : decayedRate * 1.4) / 100);
        }
      }
    } else {
      if (isDesc) {
        projected *= (1 + rate / 100);
        p25Val *= (1 + (r25 !== undefined ? r25 : rate) / 100);
        p75Val *= (1 + (r75 !== undefined ? r75 : rate) / 100);
      } else {
        projected *= (1 - rate / 100);
        p25Val *= (1 - (r25 !== undefined ? r25 : rate) / 100);
        p75Val *= (1 - (r75 !== undefined ? r75 : rate) / 100);
      }
    }
    
    points.push({
      age,
      projected: Math.round(projected * 1000) / 1000,
      p25: Math.round(p25Val * 1000) / 1000,
      p75: Math.round(p75Val * 1000) / 1000,
      n,
    });
  }
  
  return points;
}

/**
 * Get all three trajectory projections for comparison chart.
 */
export function projectAllTrajectories(currentPB, currentAge, discipline, gender, maxAge = 35) {
  return {
    early: projectPerformance(currentPB, currentAge, discipline, gender, 'early', maxAge),
    late: projectPerformance(currentPB, currentAge, discipline, gender, 'late', maxAge),
    steady: projectPerformance(currentPB, currentAge, discipline, gender, 'steady', maxAge),
  };
}

export default IMPROVEMENT_CURVES;
